struct MinMax(Copyable, Movable):
    var min: Float64
    var max: Float64

def minmax(xs: List[Float64]) -> MinMax:
    var lo = xs[0]
    var hi = xs[0]
    for i in range(1, len(xs)):
        if xs[i] < lo:
            lo = xs[i]
        if xs[i] > hi:
            hi = xs[i]
    return MinMax(lo, hi)

